import React, { useState } from 'react';
import { GoogleGenAI, Type } from "@google/genai";

const RecipeGen: React.FC = () => {
  const [ingredient, setIngredient] = useState('');
  const [loading, setLoading] = useState(false);
  const [recipe, setRecipe] = useState<any>(null);

  const generateRecipe = async () => {
    if (!ingredient.trim()) return;
    setLoading(true);
    setRecipe(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Create a healthy recipe using honey and ${ingredient}.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              recipeName: { type: Type.STRING },
              ingredients: { 
                type: Type.ARRAY,
                items: { type: Type.STRING }
              },
              instructions: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            },
            required: ["recipeName", "ingredients", "instructions"]
          }
        }
      });

      const data = JSON.parse(response.text);
      setRecipe(data);
    } catch (error) {
      console.error("Error generating recipe:", error);
      alert("Something went wrong. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="py-24 bg-[#FFF8E1] border-y border-[#FFC107]/20">
      <div className="max-w-4xl mx-auto px-4 text-center">
        <h2 className="text-4xl font-bold text-[#8B4513] mb-6">AI Honey Recipe Kitchen</h2>
        <p className="text-lg text-[#333333]/70 mb-8">
          Have an ingredient in your fridge? Tell us, and our AI will create a healthy honey-based recipe just for you.
        </p>

        <div className="flex flex-col sm:flex-row gap-4 mb-12 max-w-lg mx-auto">
          <input
            type="text"
            placeholder="Enter an ingredient (e.g. Avocado, Oat, Salmon)"
            className="flex-grow px-6 py-4 rounded-xl border-2 border-[#FFC107]/20 focus:border-[#FFC107] outline-none"
            value={ingredient}
            onChange={(e) => setIngredient(e.target.value)}
          />
          <button
            onClick={generateRecipe}
            disabled={loading}
            className="px-8 py-4 bg-[#FFC107] text-[#8B4513] font-bold rounded-xl hover:bg-[#FFB300] transition-all disabled:opacity-50"
          >
            {loading ? 'Cooking up...' : 'Generate Recipe'}
          </button>
        </div>

        {recipe && (
          <div className="bg-white p-8 rounded-3xl shadow-xl text-left animate-in fade-in slide-in-from-bottom-4 duration-500">
            <h3 className="text-3xl font-bold text-[#8B4513] mb-6 border-b pb-4">{recipe.recipeName}</h3>
            <div className="grid md:grid-cols-2 gap-12">
              <div>
                <h4 className="font-bold text-[#FFC107] uppercase text-sm tracking-widest mb-4">Ingredients</h4>
                <ul className="space-y-2">
                  {recipe.ingredients.map((ing: string, i: number) => (
                    <li key={i} className="flex items-start space-x-2 text-gray-700">
                      <span className="text-[#FFC107] mt-1">•</span>
                      <span>{ing}</span>
                    </li>
                  ))}
                </ul>
              </div>
              <div>
                <h4 className="font-bold text-[#FFC107] uppercase text-sm tracking-widest mb-4">Instructions</h4>
                <ol className="space-y-4">
                  {recipe.instructions.map((step: string, i: number) => (
                    <li key={i} className="flex space-x-4">
                      <span className="flex-shrink-0 w-6 h-6 rounded-full bg-[#FFC107] text-[#8B4513] text-xs font-bold flex items-center justify-center">
                        {i + 1}
                      </span>
                      <p className="text-gray-700 leading-relaxed">{step}</p>
                    </li>
                  ))}
                </ol>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default RecipeGen;

