import React, { useState, useMemo } from 'react';
import { MOCK_PRODUCTS } from '../constants';
import { useCart } from '../App';

const Hero: React.FC = () => {
  const { addToCart } = useCart();
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    address: '',
    productId: MOCK_PRODUCTS[0].id,
    quantity: 1,
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const product = MOCK_PRODUCTS.find(p => p.id === formData.productId);
    if (product) {
      addToCart(product, Number(formData.quantity));
      alert(`Success! ${formData.quantity}x ${product.name} added to your order.`);
    }
  };

  // Group products by type for the selection category feature
  const groupedProducts = useMemo(() => {
    const groups: Record<string, typeof MOCK_PRODUCTS> = {};
    MOCK_PRODUCTS.forEach(p => {
      if (!groups[p.type]) groups[p.type] = [];
      groups[p.type].push(p);
    });
